index 00000000..7f2b3108
--- /dev/null
+++ b/server/blocker_auth_test.go
@@ -0,0 +1,25 @@
+package server
+
+import (
+	"net/http"
+	"strings"
+	"testing"
+
+	"github.com/navidrome/navidrome/consts"
+)
+
+func TestBlocker2MaxTokenLength(t *testing.T) {
+	validToken := strings.Repeat("x", 2000)
+	r, _ := http.NewRequest(http.MethodGet, "/", nil)
+	r.Header.Set(consts.UIAuthorizationHeader, "Bearer "+validToken)
+	if got := tokenFromHeader(r); got != validToken {
+		t.Errorf("2000-char token must be accepted, got empty")
+	}
+
+	oversizedToken := strings.Repeat("x", 2001)
+	r, _ = http.NewRequest(http.MethodGet, "/", nil)
+	r.Header.Set(consts.UIAuthorizationHeader, "Bearer "+oversizedToken)
+	if got := tokenFromHeader(r); got != "" {
+		t.Errorf("2001-char token must be rejected, got len=%d", len(got))
+	}
+}
